#include <stdio.h>
#include <pthread.h>
#include <unistd.h>

/*
 * Peterson's Solution for Two Processes
 * Demonstrates software-based mutual exclusion
 */

// Shared variables for Peterson's solution
volatile int turn; // Whose turn is it?
volatile int flag[2]; // flag[i] = 1 means process i wants to enter

// Shared resource counter
volatile int shared_counter = 0;

// Mutex for safe printing
pthread_mutex_t print_mutex = PTHREAD_MUTEX_INITIALIZER;

/*
 * Peterson's Entry Protocol for Process i
 * i: process ID (0 or 1)
 */
void peterson_entry(int i) {
 int j = 1 - i; // The other process

 // Step 1: Announce interest in critical section
 flag[i] = 1;

 // Step 2: Give priority to the other process (courtesy)
 turn = j;

 // Step 3: Wait while other process wants to enter AND it's their turn
 // This is the busy-wait (spinlock) condition
 while (flag[j] == 1 && turn == j) {
 // Busy waiting - processor spins here
 }
 // Now we can safely enter critical section
}

/*
 * Peterson's Exit Protocol for Process i
 * i: process ID (0 or 1)
 */
void peterson_exit(int i) {
 // Step 4: Signal we are done with critical section
 flag[i] = 0;
}

/*
 * Process thread function
 */
void* process_function(void* arg) {
 int i = *((int*)arg); // Get process ID (0 or 1)
 int j = 1 - i; // Other process ID

 for (int iteration = 0; iteration < 5; iteration++) {
 // Entry Section
 peterson_entry(i);

 // === CRITICAL SECTION ===
 pthread_mutex_lock(&print_mutex);
 printf(" >>> Process %d ENTERED critical section (iteration %d)\n", i, iteration + 1);
 pthread_mutex_unlock(&print_mutex);

 // Access shared resource - increment counter
 shared_counter++;
 int temp = shared_counter;
 usleep(1000); // Simulate some work

 pthread_mutex_lock(&print_mutex);
 printf(" <<< Process %d EXITED critical section\n", i, iteration + 1);
 pthread_mutex_unlock(&print_mutex);

 // Exit Section
 peterson_exit(i);

 // Remainder Section - do non-critical work
 usleep(500);
 }

 pthread_mutex_lock(&print_mutex);
 printf("Process %d completed all iterations\n", i);
 pthread_mutex_unlock(&print_mutex);

 return NULL;
}

int main() {
 pthread_t thread0, thread1;
 int id0 = 0, id1 = 1;

 // Initialize shared variables
 turn = 0;
 flag[0] = 0;
 flag[1] = 0;
 shared_counter = 0;

 printf("========================================\n");
 printf("Peterson's Solution - Critical Section\n");
 printf("========================================\n\n");

 // Create two process threads
 pthread_create(&thread0, NULL, process_function, &id0);
 pthread_create(&thread1, NULL, process_function, &id1);

 // Wait for both threads to complete
 pthread_join(thread0, NULL);
 pthread_join(thread1, NULL);

 printf("\n========================================\n");
 printf("RESULTS:\n");
 printf(" Final shared counter value: %d\n", shared_counter);
 printf(" Expected value: 10 (5 + 5)\n");
 printf(" Mutual Exclusion: MAINTAINED\n");
 printf("========================================\n");

 return 0;
}
